# Category: graphql_security

from ariadne import QueryType, make_executable_schema, gql
from ariadne.asgi import GraphQL
from starlette.applications import Starlette
from starlette.middleware.base import BaseHTTPMiddleware
from starlette.requests import Request
from starlette.responses import JSONResponse

type_defs = gql("""
    type Query {
        user(id: ID!): User
        users: [User!]!
    }

    type User {
        id: ID!
        username: String!
        bio: String
        email: String
        phone: String
        address: String
        posts: [Post!]!
    }

    type Post {
        id: ID!
        title: String!
        content: String
        author: User!
    }
""")

USERS = [
    {
        "id": "1",
        "username": "alice",
        "bio": "Backend engineer",
        "email": "alice@example.com",
        "phone": "111-222-3333",
        "address": "123 Main St",
    },
    {
        "id": "2",
        "username": "bob",
        "bio": "Frontend developer",
        "email": "bob@example.com",
        "phone": "222-333-4444",
        "address": "456 Oak Ave",
    },
]

POSTS = [
    {
        "id": "1",
        "title": "Hello GraphQL",
        "content": "Getting started with GraphQL.",
        "author_id": "1",
    },
    {
        "id": "2",
        "title": "Ariadne Tips",
        "content": "Resolvers made simple.",
        "author_id": "1",
    },
    {
        "id": "3",
        "title": "UI Patterns",
        "content": "Designing reusable components.",
        "author_id": "2",
    },
]

query = QueryType()

def get_user_by_id(user_id: str):
    return next((user for user in USERS if user["id"] == str(user_id)), None)

def get_posts_by_author_id(author_id: str):
    return [post for post in POSTS if post["author_id"] == str(author_id)]

@query.field("user")
def resolve_user(_, info, id):
    current_user = info.context.get("current_user")
    return get_user_by_id(id)

@query.field("users")
def resolve_users(_, info):
    current_user = info.context.get("current_user")
    return USERS

def resolve_user_posts(user, info):
    return get_posts_by_author_id(user["id"])

def resolve_post_author(post, info):
    return get_user_by_id(post["author_id"])

schema = make_executable_schema(
    type_defs,
    query,
    {
        "User": {
            "posts": resolve_user_posts,
        },
        "Post": {
            "author": resolve_post_author,
        },
    },
)

class FakeAuthMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request: Request, call_next):
        request.state.current_user = get_user_by_id("1")
        return await call_next(request)

async def context_value(request: Request):
    return {
        "request": request,
        "current_user": getattr(request.state, "current_user", None),
    }

graphql_app = GraphQL(schema, context_value=context_value, debug=True)

app = Starlette()
app.add_middleware(FakeAuthMiddleware)
app.mount("/graphql", graphql_app)

@app.route("/")
async def homepage(request: Request):
    return JSONResponse({"message": "GraphQL API available at /graphql"})